import{_ as a,o as s,c as t,ao as i}from"./chunks/framework.B8HPK1Aj.js";const u=JSON.parse('{"title":"The data folder","description":"","frontmatter":{},"headers":[],"relativePath":"data-folder.md","filePath":"data-folder.md","lastUpdated":null}'),o={name:"data-folder.md"};function n(l,e,r,d,c,h){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="The-data-folder" tabindex="-1">The data folder <a class="header-anchor" href="#The-data-folder" aria-label="Permalink to &quot;The data folder {#The-data-folder}&quot;">​</a></h1><p>Fromage works on one folder that holds your videos and two spreadsheet files: <code>calibs.csv</code> (your calibration videos) and <code>runs.csv</code> (your run videos). This page covers how to lay that folder out, and the writing rules that both csv files share.</p><h2 id="The-simplest-layout" tabindex="-1">The simplest layout <a class="header-anchor" href="#The-simplest-layout" aria-label="Permalink to &quot;The simplest layout {#The-simplest-layout}&quot;">​</a></h2><p>Everything in one folder:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my experiment/</span></span>
<span class="line"><span>├── calibs.csv</span></span>
<span class="line"><span>├── runs.csv</span></span>
<span class="line"><span>├── calib_morning.mp4</span></span>
<span class="line"><span>├── calib_afternoon.mp4</span></span>
<span class="line"><span>├── beetle01.mp4</span></span>
<span class="line"><span>├── beetle02.mp4</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><p>and then:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path/to/my experiment&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="Other-layouts" tabindex="-1">Other layouts <a class="header-anchor" href="#Other-layouts" aria-label="Permalink to &quot;Other layouts {#Other-layouts}&quot;">​</a></h2><p>The csv files can be named differently or live in subfolders:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path/to/my experiment&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; calibs_file </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;meta/my_calibs.csv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, runs_file </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;meta/my_runs.csv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>And the video files can live in other folders via the <code>path</code> column in either csv file. Paths are relative to the folder the csv file itself is in; absolute paths work too.</p><h2 id="Editing-csv-files" tabindex="-1">Editing csv files <a class="header-anchor" href="#Editing-csv-files" aria-label="Permalink to &quot;Editing csv files {#Editing-csv-files}&quot;">​</a></h2><p>A csv file is just a table saved as plain text — you can edit it in Excel, Google Sheets, LibreOffice, or any text editor. Just make sure it&#39;s saved as <strong>.csv</strong>, not .xlsx. Template files to copy from live in <a href="https://github.com/yakir12/Fromage.jl/tree/main/examples" target="_blank" rel="noreferrer"><code>examples/</code></a>.</p><h2 id="Rules-both-csv-files-share" tabindex="-1">Rules both csv files share <a class="header-anchor" href="#Rules-both-csv-files-share" aria-label="Permalink to &quot;Rules both csv files share {#Rules-both-csv-files-share}&quot;">​</a></h2><ul><li><p>Column <strong>order doesn&#39;t matter</strong>, and optional columns may be left out entirely.</p></li><li><p>A <strong>blank cell</strong> in an optional column means &quot;use the default&quot; — so a column can be filled in for some rows and left blank for others.</p></li><li><p><strong>Unrecognized column names are an error.</strong> This protects you from typos (a misspelled column would otherwise be silently ignored). Both files accept a free-text <code>comment</code> column, which is ignored — put your notes there.</p></li></ul><h3 id="Writing-timestamps" tabindex="-1">Writing timestamps <a class="header-anchor" href="#Writing-timestamps" aria-label="Permalink to &quot;Writing timestamps {#Writing-timestamps}&quot;">​</a></h3><p>Timestamps (<code>start</code>, <code>stop</code>, <code>extrinsic</code>) are either a number of seconds (e.g. <code>12.345</code>) or a clock time <code>HH:MM:SS.mmm</code> (e.g. <code>00:02:09.123</code>; milliseconds optional).</p><div class="danger custom-block"><p class="custom-block-title">The most common timestamp mistake</p><p>Always write all three clock parts: <code>01:30</code> means <strong>1 hour 30 minutes</strong>, <em>not</em> 1 minute 30 seconds. If in doubt, use plain seconds.</p></div><h3 id="Writing-pixel-coordinates" tabindex="-1">Writing pixel coordinates <a class="header-anchor" href="#Writing-pixel-coordinates" aria-label="Permalink to &quot;Writing pixel coordinates {#Writing-pixel-coordinates}&quot;">​</a></h3><p>Pixel coordinates (<code>start_location</code>, <code>center</code>, <code>north</code>) are written <code>&quot;(x, y)&quot;</code> — <strong>including the quotes</strong>, since the cell contains a comma. <code>x</code> is the distance in pixels from the <em>left</em> edge of the frame and <code>y</code> from the <em>top</em> edge, exactly as an image viewer (GIMP, Photoshop, etc.) reports them when you hover over a paused frame.</p><div class="tip custom-block"><p class="custom-block-title">How to find a pixel coordinate</p><p>Pause the video on a good frame, take a screenshot (or export the frame), open it in an image viewer, and hover the mouse over the point you want — the viewer shows the <code>(x, y)</code> position of the cursor.</p></div><h2 id="Next" tabindex="-1">Next <a class="header-anchor" href="#Next" aria-label="Permalink to &quot;Next {#Next}&quot;">​</a></h2><ul><li><p><a href="./runs">runs.csv →</a></p></li><li><p><a href="./calibs">calibs.csv →</a></p></li></ul>`,23)])])}const m=a(o,[["render",n]]);export{u as __pageData,m as default};
